" 
echo "=== FRAGMENTS ==="; cat "$SP/planner-contributions.md"

PHASE_DIR="/home/janfr/dev/pc-switcher/.planning/phases/02-package-management-sync"
echo "=== package_items.py writers (files_modified) ==="
for f in "$PHASE_DIR"/*-PLAN.md; do
  b=$(basename "$f" -PLAN.md)
  w=$(grep -m1 '^wave:' "$f" | tr -d ' ' | cut -d: -f2)
  if awk '/^files_modified:/{fl=1;next} /^[a-z_]+:/{fl=0} fl' "$f" | grep -q 'package_items\.py'; then
    echo "  $b (wave $w) WRITES package_items.py"
  fi
done
echo; echo "=== wave 5 depends_on ==="
for f in 02-07 02-08 02-09; do printf "  %s: " "$f"; grep -m1 '^depends_on:' "$PHASE_DIR/$f-PLAN.md"; done
echo; echo "=== residual hedging ==="
grep -rn "if not already present\|if it is not already there" "$PHASE_DIR"/*-PLAN.md || echo "  none"
echo; echo "=== same-wave files_modified overlap check ==="
node -e '
const fs=require("fs"),path=require("path");
const dir="'"$PHASE_DIR"'";
const waves={};
for(const f of fs.readdirSync(dir).filter(f=>f.endsWith("-PLAN.md"))){
  const t=fs.readFileSync(path.join(dir,f),"utf8");
  const w=(t.match(/^wave:\s*(\S+)/m)||[])[1];
  const fmBlock=(t.match(/^files_modified:\n((?:\s+-\s.*\n)+)/m)||[])[1]||"";
  const files=fmBlock.split("\n").map(l=>l.replace(/^\s*-\s*/,"").trim()).filter(Boolean);
  (waves[w]=waves[w]||[]).push({plan:f.replace("-PLAN.md",""),files});
}
let bad=0;
for(const [w,plans] of Object.entries(waves).sort()){
  for(let i=0;i<plans.length;i++)for(let j=i+1;j<plans.length;j++){
    const ov=plans[i].files.filter(x=>plans[j].files.includes(x));
    if(ov.length){bad++;console.log("  OVERLAP wave "+w+": "+plans[i].plan+" ^ "+plans[j].plan+" -> "+ov.join(", "));}
  }
}
console.log(bad?("  "+bad+" overlap(s)"):"  no same-wave overlaps across "+Object.keys(waves).length+" waves");
'
echo; echo "=== commits ==="; git log --oneline -3

